import React, { useState, useEffect } from 'react';
import axios from 'axios';

function ClientDashboard() {
  const [projects, setProjects] = useState([]);
  const [loading, setLoading] = useState(true);

  // १. सीधे डेटाबेस से सभी प्रोजेक्ट्स लोड करना
  useEffect(() => {
    const fetchAllProjects = async () => {
      try {
        const res = await axios.get('http://localhost:5000/api/requests');
        setProjects(res.data);
        setLoading(false);
      } catch (err) {
        console.error("Error fetching data:", err);
        setLoading(false);
      }
    };
    fetchAllProjects();
  }, []);

  if (loading) return <div className="text-center py-5">Loading Dashboard...</div>;

  return (
    <div className="container py-5 mt-4">
      <h2 className="fw-bold text-center mb-5 text-primary">Clients Project Status</h2>
      
      <div className="row g-4 justify-content-center">
        {projects.map((project) => (
          <div key={project._id} className="col-lg-10">
            <div className="card shadow-sm border-0 rounded-4 overflow-hidden mb-3">
              
              {/* Header */}
              <div className="bg-light p-3 border-bottom d-flex justify-content-between align-items-center">
                <div>
                  <h5 className="mb-0 fw-bold">{project.fullName}</h5>
                  <small className="text-muted">{project.serviceType}</small>
                </div>
                <span className={`badge p-2 px-3 rounded-pill ${project.paymentStatus === 'Paid' ? 'bg-success' : 'bg-warning text-dark'}`}>
                  {project.paymentStatus === 'Paid' ? '✅ Fully Paid' : '⏳ Payment Pending'}
                </span>
              </div>
              
              <div className="card-body p-4">
                {/* Progress Bar */}
                <div className="mb-4">
                  <div className="d-flex justify-content-between mb-2">
                    <span className="small fw-bold text-muted">Project Progress</span>
                    <span className="fw-bold text-primary">{project.progress}% Done</span>
                  </div>
                  <div className="progress rounded-pill shadow-none" style={{ height: '20px', backgroundColor: '#e9ecef' }}>
                    <div 
                      className="progress-bar progress-bar-striped progress-bar-animated bg-success" 
                      style={{ width: `${project.progress}%` }}
                    ></div>
                  </div>
                </div>

                {/* Info Section */}
                <div className="row text-center bg-light rounded-3 p-3 g-2">
                  <div className="col-md-4 border-end">
                    <small className="d-block text-muted">Total Budget</small>
                    <span className="fw-bold">₹{project.totalBudget}</span>
                  </div>
                  <div className="col-md-4 border-end">
                    <small className="d-block text-muted">Advance Paid</small>
                    <span className="fw-bold text-success">₹{project.advancePaid}</span>
                  </div>
                  <div className="col-md-4">
                    <small className="d-block text-muted">Remaining Balance</small>
                    <span className="fw-bold text-danger">₹{project.totalBudget - project.advancePaid}</span>
                  </div>
                </div>
              </div>

            </div>
          </div>
        ))}

        {projects.length === 0 && <div className="text-center text-muted">No projects found.</div>}
      </div>
    </div>
  );
}

export default ClientDashboard;
